import{_ as e,c as a,o as t,a as r}from"./app.fc4dff93.js";const f=JSON.parse('{"title":"\u4ECE\u5927\u5B66\u5230\u804C\u573A\uFF0C\u6211\u5728\u6C89\u6DC0\u4E2D\u79EF\u84C4\u529B\u91CF","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u6700\u540E\u7684\u6821\u56ED\u65F6\u5149","slug":"\u6700\u540E\u7684\u6821\u56ED\u65F6\u5149","link":"#\u6700\u540E\u7684\u6821\u56ED\u65F6\u5149","children":[]},{"level":2,"title":"\u521D\u5165\u804C\u573A","slug":"\u521D\u5165\u804C\u573A","link":"#\u521D\u5165\u804C\u573A","children":[]},{"level":2,"title":"\u4E1A\u4F59\u7231\u597D\u505A\u51CF\u6CD5","slug":"\u4E1A\u4F59\u7231\u597D\u505A\u51CF\u6CD5","link":"#\u4E1A\u4F59\u7231\u597D\u505A\u51CF\u6CD5","children":[]},{"level":2,"title":"\u5C55\u671B 2023","slug":"\u5C55\u671B-2023","link":"#\u5C55\u671B-2023","children":[]}],"relativePath":"experience/work/2022-year-end-review.md","lastUpdated":1672671275000}'),i={name:"experience/work/2022-year-end-review.md"},p=r('<h1 id="\u4ECE\u5927\u5B66\u5230\u804C\u573A\uFF0C\u6211\u5728\u6C89\u6DC0\u4E2D\u79EF\u84C4\u529B\u91CF" tabindex="-1">\u4ECE\u5927\u5B66\u5230\u804C\u573A\uFF0C\u6211\u5728\u6C89\u6DC0\u4E2D\u79EF\u84C4\u529B\u91CF <a class="header-anchor" href="#\u4ECE\u5927\u5B66\u5230\u804C\u573A\uFF0C\u6211\u5728\u6C89\u6DC0\u4E2D\u79EF\u84C4\u529B\u91CF" aria-hidden="true">#</a></h1><p>\u300C\u56DE\u987E2022\uFF0C\u5C55\u671B2023\uFF0C\u6211\u6B63\u5728\u53C2\u4E0E<a href="https://juejin.cn/post/7172462429929111559" title="https://juejin.cn/post/7172462429929111559" target="_blank" rel="noreferrer">2022\u5E74\u7EC8\u603B\u7ED3\u5F81\u6587\u5927\u8D5B\u6D3B\u52A8</a>\u300D</p><p>2022 \u5E74 12 \u6708 31 \u65E5\uFF0C\u5728\u65B0\u5E74\u7684\u5012\u8BA1\u65F6\u4E0B\uFF0C\u6211\u51C6\u5907\u603B\u7ED3\u8FC7\u53BB\u4E00\u5E74\u3002\u4F5C\u4E3A\u4E00\u540D 00 \u540E\uFF0C\u5904\u5728 20 \u591A\u5C81\u7684\u5E74\u7EAA\uFF0C\u6211\u539F\u672C\u60F3\u628A\u8FD9\u7BC7\u603B\u7ED3\u5199\u5F97\u66F4\u300C\u610F\u6C14\u98CE\u53D1\u300D\u4E9B\uFF0C\u4F46\u5C1D\u8BD5\u8BB8\u4E45\uFF0C\u59CB\u7EC8\u4E0D\u80FD\u5982\u613F\u3002</p><p>\u60F3\u6765\u4E5F\u662F\uFF0C\u8FC7\u53BB\u4E00\u5E74\u5927\u73AF\u5883\u4E0D\u597D\uFF0C\u5927\u5BB6\u90FD\u5728\u8BF4\u4E92\u8054\u7F51\u7684\u5BD2\u51AC\u5DF2\u81F3\uFF0C\u6211\u4E5F\u662F\u5904\u5904\u6C42\u7A33\uFF0C\u81EA\u7136\u6CA1\u6709\u300C\u52C3\u52C3\u751F\u673A\u300D\u7684\u611F\u89C9\u3002\u4E5F\u7F62\uFF0C\u5C31\u8C08\u8C08\u6211\u8FC7\u53BB\u6C42\u7A33\u7684\u4E00\u5E74\u5427\u3002</p><h2 id="\u6700\u540E\u7684\u6821\u56ED\u65F6\u5149" tabindex="-1">\u6700\u540E\u7684\u6821\u56ED\u65F6\u5149 <a class="header-anchor" href="#\u6700\u540E\u7684\u6821\u56ED\u65F6\u5149" aria-hidden="true">#</a></h2><p>\u6700\u540E\u7684\u6821\u56ED\u65F6\u5149\u91CC\uFF0C\u6211\u7684\u6BD5\u4E1A\u8BBE\u8BA1\u505A\u5F97\u5F88\u8BA4\u771F\u3002\u8FD9\u5012\u4E0D\u662F\u56E0\u4E3A\u6211\u9189\u5FC3\u5B66\u672F\u3001\u75F4\u8FF7\u79D1\u7814\uFF0C\u800C\u662F\u56E0\u4E3A\u6211\u6B64\u65F6\u5DF2\u7ECF\u548C\u7F8E\u56E2\u7B7E\u4E86\u4E09\u65B9\u534F\u8BAE\uFF0C\u4E0D\u60F3\u5728\u6BD5\u4E1A\u8BBE\u8BA1\u4E0A\u51FA\u4EC0\u4E48\u5C94\u5B50\u3002</p><p>\u5F53\u65F6\uFF0C\u5BFC\u5E08\u5E0C\u671B\u6211\u80FD\u7ED3\u5408\u524D\u7AEF\u77E5\u8BC6\u548C\u4EBA\u5DE5\u667A\u80FD\uFF0C\u505A\u4E00\u4E9B\u4EE3\u7801\u81EA\u52A8\u751F\u6210\u7684\u63A2\u7D22\u3002</p><p>\u4F5C\u4E3A\u4E00\u540D\u524D\u7AEF\u5DE5\u7A0B\u5E08\uFF0C\u6211\u5F88\u719F\u6089\u524D\u7AEF\u77E5\u8BC6\u3002\u4F46\u5BF9\u4E8E\u4EBA\u5DE5\u667A\u80FD\uFF0C\u6211\u4E00\u65E0\u6240\u77E5\u3002\u8981\u7ED3\u5408\u4EBA\u5DE5\u667A\u80FD\u548C\u524D\u7AEF\uFF0C\u6211\u529B\u4E0D\u4ECE\u5FC3\u3002</p><p>\u6211\u6076\u8865\u4E86\u4E00\u6BB5\u65F6\u95F4\u7684\u4EBA\u5DE5\u667A\u80FD\uFF08<s>\u6BD5\u4E1A\u540E\u5C31\u5168\u5FD8\u4E86</s>\uFF09\uFF0C\u7528\u82E6\u6DA9\u4E4F\u5473\u7684\u8BED\u8A00\uFF0C\u5728\u6BD5\u4E1A\u8BBA\u6587\u4E0A\u5199\u4E0B\u4E86\u6211\u82CD\u767D\u65E0\u529B\u7684\u601D\u8003\u3002</p><p>\u8003\u8651\u5230\u4EBA\u5DE5\u667A\u80FD\u90E8\u5206\uFF0C\u6DF1\u5EA6\u548C\u5E7F\u5EA6\u80AF\u5B9A\u4E0D\u591F\uFF0C\u6211\u5728\u524D\u7AEF\u90E8\u5206\u591A\u4E0B\u4E86\u529F\u592B\uFF0C\u505A\u4E86\u4E09\u4E2A\u524D\u7AEF Demo\uFF1A</p><ul><li>\u4F4E\u4EE3\u7801\uFF08\u4E5E\u4E10\u7248\u7684 Dreamweaver\uFF09</li><li>\u6A21\u677F\u5F15\u64CE\uFF08\u4E5E\u4E10\u7248\u7684 EJS\uFF09</li><li>\u9759\u6001\u7F51\u9875\u751F\u6210\u5668\uFF08\u4E5E\u4E10\u7248\u7684 VuePress\uFF09</li></ul><p>\u7528\u8FD9\u4E09\u4E2A Demo\uFF0C\u6211\u89E3\u91CA\u4E86\u751F\u6210\u524D\u7AEF\u4EE3\u7801\u7684\u65B9\u6CD5\u548C\u539F\u7406\u3002\u539F\u672C\u6D45\u8584\u7684\u6BD5\u4E1A\u8BBA\u6587\uFF0C\u4E5F\u7B97\u6709\u4E86\u4E9B\u6DF1\u5EA6\u548C\u5E7F\u5EA6\u3002</p><p>\u6CA1\u6709\u591A\u5C11\u6CE2\u6F9C\uFF0C\u6211\u5982\u613F\u4EE5\u507F\u5730\u5B89\u7A33\u6BD5\u4E1A\u3002\u6BD5\u4E1A\u65F6\u6211\u7684\u60C5\u7EEA\u5F88\u5FAE\u5999\uFF0C\u4E0D\u600E\u4E48\u4F24\u5FC3\uFF0C\u4E5F\u4E0D\u600E\u4E48\u6000\u5FF5\u3002</p><h2 id="\u521D\u5165\u804C\u573A" tabindex="-1">\u521D\u5165\u804C\u573A <a class="header-anchor" href="#\u521D\u5165\u804C\u573A" aria-hidden="true">#</a></h2><p>\u6211\u66FE\u7ECF\u5728\u77E5\u4E4E\u5B9E\u4E60\u8FC7\uFF0C\u505A\u7684\u662F B \u7AEF\u7684\u5DE5\u4F5C\uFF0C\u5177\u4F53\u6765\u8BF4\u5C31\u662F\u7528 React + Ant Design + Echarts \u505A\u4E00\u4E9B\u56FE\u8868\u3001\u8868\u5355\u7B49\u3002</p><p>\u6709\u4E86\u5B9E\u4E60\u7ECF\u9A8C\uFF0C\u6211\u539F\u672C\u4EE5\u4E3A\u81EA\u5DF1\u771F\u6B63\u5DE5\u4F5C\u65F6\uFF0C\u80FD\u591F\u5F97\u5FC3\u5E94\u624B\uFF0C\u53EF\u5B9E\u9645\u7684\u5DE5\u4F5C\u6BD4\u6211\u9884\u60F3\u8981\u590D\u6742\u3002</p><p>\u6211\u5728\u7F8E\u56E2\u505A\u7684\u662F C \u7AEF\u7684\u5DE5\u4F5C\u3002\u6280\u672F\u6808\u6BD4\u8F83\u6742\uFF0C\u5927\u81F4\u5206\u4E3A\u4E09\u5927\u5757\uFF1A\u5FAE\u4FE1\u5C0F\u7A0B\u5E8F\u3001React Native \u548C Vue\u3002\u4E0D\u8FC7\u6211\u6709\u4E0D\u9519\u7684 JavaScript \u57FA\u7840\uFF0C\u4E5F\u5199\u8FC7 Vue\u3001React \u548C\u5FAE\u4FE1\u5C0F\u7A0B\u5E8F\uFF0C\u6240\u4EE5\u53EF\u4EE5\u5543\u5543\u8001\u672C\uFF0C\u4E0A\u624B\u5DE5\u4F5C\u901F\u5EA6\u8FD8\u86EE\u5FEB\u3002</p><p><strong>\u4F46\u662F\u77E5\u8BC6\u53EF\u4EE5\u5B66\u4E60\uFF0C\u7ECF\u9A8C\u5374\u53EA\u80FD\u79EF\u7D2F</strong>\u3002</p><p>\u6211\u8DDF\u7740\u51E0\u4F4D\u524D\u8F88\uFF0C\u505A\u4E86\u4E24\u4E09\u4E2A\u5FAE\u4FE1\u5C0F\u7A0B\u5E8F\u7684\u9700\u6C42\uFF0C\u4E09\u56DB\u4E2A React Native \u9700\u6C42\uFF0C\u624D\u9010\u6E10\u719F\u6089\u4E86\u57CB\u70B9\u3001\u8054\u8C03\u3001\u6D4B\u8BD5\u3001\u6253\u5305\u3001\u7070\u5EA6\u3001\u56DE\u6EDA\u7B49\u5404\u79CD\u6D41\u7A0B\u3002\u9700\u6C42\u8BC4\u5BA1\u65F6\uFF0C\u6211\u867D\u7136\u5728\u65C1\u8FB9\u503E\u542C\uFF0C\u4F46\u4E5F\u53EA\u662F\u56EB\u56F5\u541E\u67A3\u3002</p><p>\u5728\u8FD9\u671F\u95F4\uFF0C\u6211\u65E0\u6CD5\u89E3\u51B3\u7684\u95EE\u9898\uFF0C\u90FD\u662F\u524D\u8F88\u4EEC\u515C\u7684\u5E95\u3002\u6BCF\u5F53\u8FD9\u65F6\uFF0C\u6211\u90FD\u4F1A\u6697\u6697\u628A\u8FD9\u4E9B\u95EE\u9898\u603B\u7ED3\u6574\u7406\uFF0C\u4EE5\u514D\u4E0B\u6B21\u518D\u72AF\u3002<strong>\u80FD\u529B\u53EF\u4EE5\u6682\u65F6\u6CA1\u6709\uFF0C\u6001\u5EA6\u5FC5\u987B\u6446\u6B63</strong>\u3002</p><p>\u6240\u5E78\u6211\u4E5F\u8FD8\u7B97\u4E89\u6C14\uFF0C2022 \u5E74\u7ED3\u675F\u4E86\uFF0C\u6CA1\u51FA\u5565\u5927\u95EE\u9898\uFF0C\u7B97\u662F\u82DF\u8FC7\u4E86\u521D\u5165\u804C\u573A\u7684\u65B0\u624B\u671F\u3002</p><h2 id="\u4E1A\u4F59\u7231\u597D\u505A\u51CF\u6CD5" tabindex="-1">\u4E1A\u4F59\u7231\u597D\u505A\u51CF\u6CD5 <a class="header-anchor" href="#\u4E1A\u4F59\u7231\u597D\u505A\u51CF\u6CD5" aria-hidden="true">#</a></h2><p>\u6211\u5728\u5927\u5B66\u65F6\u7CBE\u529B\u5F88\u5145\u6C9B\uFF0C\u5F00\u4E86\u5F88\u591A\u5751\uFF0C\u5305\u62EC\u4F46\u4E0D\u9650\u4E8E\uFF1A</p><ol><li>\u8D2D\u4E70\u57DF\u540D\u3001\u670D\u52A1\u5668\uFF0C\u641E\u4E2A\u4EBA\u7F51\u7AD9</li><li>\u6CE8\u518C\u5FAE\u4FE1\u516C\u4F17\u53F7\u3001\u8BED\u96C0\u3001\u77E5\u4E4E\u3001\u7B80\u4E66\u3001CSDN\u3001\u535A\u5BA2\u56ED\u3001\u6398\u91D1</li><li>\u5F00\u901A\u5FAE\u4FE1\u4E91\u5F00\u53D1\uFF0C\u641E\u4E2A\u4EBA\u7684\u5FAE\u4FE1\u5C0F\u7A0B\u5E8F</li></ol><p>\u8FC7\u53BB\u4E00\u5E74\uFF0C\u4E00\u4E9B\u4E8B\u60C5\u7684\u51FA\u73B0\u6539\u53D8\u4E86\u6211\u7684\u60F3\u6CD5\u30028 \u6708\u65F6\uFF0C\u5FAE\u4FE1\u4E91\u5F00\u53D1\u8C03\u6574\u7684\u6536\u8D39\u7B56\u7565\uFF1B11 \u6708\u65F6\uFF0C\u8BED\u96C0\u8C03\u6574\u4E86\u6536\u8D39\u7B56\u7565\uFF1B12 \u6708\u65F6\uFF0C\u6211\u7684\u57DF\u540D\u548C\u670D\u52A1\u5668\u53C8\u9700\u8981\u7EED\u8D39\u4E86\u3002</p><p>\u6211\u4E00\u7422\u78E8\uFF0C\u81EA\u5DF1\u6316\u5751\u592A\u591A\uFF0C\u7CBE\u529B\u548C\u8D22\u529B\u88AB\u6D6A\u8D39\u4E86\u3002\u4E8E\u662F\u6211\u524A\u51CF\u4E86\u81EA\u5DF1\u7684\u4E1A\u4F59\u7231\u597D\uFF1A\u6CE8\u9500\u4E86\u57DF\u540D\uFF0C\u4E0D\u518D\u7EED\u8D39\u670D\u52A1\u5668\uFF0C\u4E0D\u518D\u8FD0\u8425\u5FAE\u4FE1\u516C\u4F17\u53F7\u3001\u8BED\u96C0\u548C\u77E5\u4E4E\uFF0C\u4E5F\u4E0D\u518D\u641E\u4E91\u5F00\u53D1\u7684\u5C0F\u7A0B\u5E8F\u3002</p><p>\u4F46\u4E2A\u4EBA\u79EF\u7D2F\u8FD8\u662F\u8981\u505A\u7684\uFF0C\u4ED4\u7EC6\u601D\u7D22\u540E\uFF0C\u6211\u7FFB\u51FA\u4E86 VitePress\uFF0C\u6363\u9F13\u6363\u9F13\u540E\u90E8\u7F72\u5230 GitHub Pages\uFF08\u4EE5\u540E\u8BB0\u7B14\u8BB0\u5C31\u5168\u9760\u5B83\u4E86\uFF09\u3002\u53E6\u5916\uFF0C\u6211\u628A\u79EF\u7070\u7684\u6398\u91D1\u8D26\u53F7\u7FFB\u4E86\u51FA\u6765\uFF0C\u6BD5\u7ADF\u6398\u91D1\u662F\u5C11\u6570\u6211\u5199\u6587\u7AE0\u8FD8\u6709\u4EBA\u770B\u7684\u793E\u533A\u3002</p><h2 id="\u5C55\u671B-2023" tabindex="-1">\u5C55\u671B 2023 <a class="header-anchor" href="#\u5C55\u671B-2023" aria-hidden="true">#</a></h2><p>\u4E00\u822C\u6765\u8BF4\uFF0C\u4E00\u4E2A\u804C\u573A\u83DC\u9E1F\u53D8\u6210\u8001\u624B\uFF0C\u9700\u8981\u4E24\u5230\u4E09\u5E74\u7684\u65F6\u95F4\u30022023 \u5E74\uFF0C\u6211\u5E0C\u671B\u81EA\u5DF1\u80FD\u591F\u6212\u9A84\u6212\u8E81\uFF0C\u8BA4\u771F\u79EF\u7D2F\u7ECF\u9A8C\u3002\u5728\u6B64\u57FA\u7840\u4E0A\uFF0C\u5982\u679C\u6211\u8FD8\u80FD\u5199\u4F18\u96C5\u7684\u4EE3\u7801\uFF0C\u66F4\u522B\u81F4\u7684\u6587\u7AE0\uFF0C\u90A3\u5C31\u518D\u597D\u4E0D\u8FC7\u4E86\u3002</p>',29),n=[p];function l(s,d,c,h,o,_){return t(),a("div",null,n)}const v=e(i,[["render",l]]);export{f as __pageData,v as default};
